import Foundation

struct CategoryContent9 {
    static let aiHistory = CategoryData(
        id: "ai_history", name: "The Story of AI", icon: "clock.arrow.circlepath", colorName: "aiBrown",
        description: "The people and breakthroughs that built AI",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 8,
        unlockRequirement: .completeCategoryMinimum("how_ai_learns")
    )
    static let lesson1 = LessonData(id: "aih_l1", title: "The Birth of AI", description: "How it all began", categoryId: "ai_history", questions: [
        Question(id: "aih1_q1", type: .multipleChoice, questionText: "The term 'Artificial Intelligence' was coined in:", options: ["1956 at the Dartmouth Conference", "1943 at the McCulloch-Pitts neural model presentation", "1969 at the first ARPANET connection", "1950 at the publication of Turing's paper"], correctAnswer: "1956 at the Dartmouth Conference", explanation: "John McCarthy coined the term at the Dartmouth Summer Research Project on AI in 1956, attended by Minsky, Shannon, and others."),
        Question(id: "aih1_q2", type: .trueFalse, questionText: "Alan Turing proposed a test for machine intelligence before the field of AI was formally established.", options: ["True", "False"], correctAnswer: "True", explanation: "Turing proposed his famous 'Imitation Game' in his 1950 paper 'Computing Machinery and Intelligence,' six years before AI became a named field."),
        Question(id: "aih1_q3", type: .fillInBlank, questionText: "The __________ Test asks whether a machine can exhibit intelligent behavior indistinguishable from a human.", options: ["Turing", "Dartmouth", "McCarthy", "Shannon"], correctAnswer: "Turing", explanation: "Alan Turing proposed this test in 1950. It remains one of the most debated benchmarks for machine intelligence, though many researchers now consider it insufficient."),
        Question(id: "aih1_q4", type: .sortOrder, questionText: "Order these AI milestones chronologically:", options: ["AI term coined (1956)", "Expert systems era (1980s)", "Turing Test proposed (1950)", "ELIZA chatbot created (1966)"], correctAnswers: ["Turing Test proposed (1950)", "AI term coined (1956)", "ELIZA chatbot created (1966)", "Expert systems era (1980s)"], explanation: "AI development progressed from theoretical foundations through early programs to practical commercial applications."),
        Question(id: "aih1_q5", type: .multipleChoice, questionText: "Who organized the 1956 Dartmouth workshop that launched AI as a formal field?", options: ["John McCarthy", "Alan Turing", "Norbert Wiener", "Claude Shannon"], correctAnswer: "John McCarthy", explanation: "John McCarthy proposed and organized the Dartmouth Conference alongside Marvin Minsky, Nathaniel Rochester, and Claude Shannon."),
        Question(id: "aih1_q6", type: .multipleChoice, questionText: "ELIZA, created by Joseph Weizenbaum at MIT in 1966, was notable because:", options: ["It was one of the first programs to simulate conversation", "It could accurately translate between languages", "It solved complex mathematical proofs", "It played chess at an expert level"], correctAnswer: "It was one of the first programs to simulate conversation", explanation: "ELIZA simulated a Rogerian therapist using simple pattern matching. Weizenbaum was alarmed that users formed emotional attachments to the program.")
    ], order: 0, difficulty: .beginner)
    static let lesson2 = LessonData(id: "aih_l2", title: "AI Winters", description: "When AI fell out of favor", categoryId: "ai_history", questions: [
        Question(id: "aih2_q1", type: .multipleChoice, questionText: "An 'AI winter' refers to:", options: ["A period of reduced funding and interest in AI research", "A seasonal slowdown in computing performance", "A deliberate pause in AI development for safety reasons", "A period when AI systems are retrained from scratch"], correctAnswer: "A period of reduced funding and interest in AI research", explanation: "AI winters were periods when inflated expectations collided with reality, causing governments and investors to slash funding."),
        Question(id: "aih2_q2", type: .trueFalse, questionText: "The history of AI includes at least two major AI winters.", options: ["True", "False"], correctAnswer: "True", explanation: "The first AI winter occurred in the 1970s after the Lighthill Report criticized AI progress. The second hit in the late 1980s when expert systems failed to scale."),
        Question(id: "aih2_q3", type: .fillInBlank, questionText: "AI winters happen when __________ about AI capabilities exceed what the technology can actually deliver.", options: ["expectations", "budgets", "timelines", "datasets"], correctAnswer: "expectations", explanation: "When grand promises are not met, the resulting disappointment leads to funding cuts, talent departures, and reduced institutional interest."),
        Question(id: "aih2_q4", type: .multipleChoice, questionText: "The 1973 Lighthill Report, which helped trigger the first AI winter, was commissioned by:", options: ["The British government", "The United States Congress", "IBM's research division", "The Japanese Ministry of Trade"], correctAnswer: "The British government", explanation: "Sir James Lighthill's critical report to the UK Science Research Council concluded that AI had failed to achieve its ambitious goals, leading to major funding cuts in Britain."),
        Question(id: "aih2_q5", type: .matchPairs, questionText: "Match AI eras:", matchPairs: [
            MatchPair(term: "1956-1974", definition: "Golden age of AI optimism"),
            MatchPair(term: "1974-1980", definition: "First AI winter"),
            MatchPair(term: "1980-1987", definition: "Expert systems boom"),
            MatchPair(term: "1987-1993", definition: "Second AI winter")
        ], explanation: "AI history has cycled between periods of breakthrough optimism and disillusionment, each time returning stronger with new approaches."),
        Question(id: "aih2_q6", type: .scenarioJudgment, questionText: "Some analysts warn that massive AI investments today resemble past hype cycles. Could another AI winter happen?", options: ["Yes, if commercial returns consistently fall short of expectations", "No, current AI capabilities make a winter impossible", "It depends on government policy alone"], correctAnswer: "Yes, if commercial returns consistently fall short of expectations", explanation: "While today's AI is far more capable, the pattern of hype cycles teaches that unsustainable expectations can still lead to pullbacks in funding and interest.")
    ], order: 1, difficulty: .intermediate)
    static let lesson3 = LessonData(id: "aih_l3", title: "Deep Learning Revolution", description: "The breakthrough that changed everything", categoryId: "ai_history", questions: [
        Question(id: "aih3_q1", type: .multipleChoice, questionText: "The modern deep learning revolution is often dated to:", options: ["2012, when AlexNet dominated the ImageNet competition", "2006, when Hinton published his deep belief network paper", "1998, when LeCun demonstrated LeNet for digit recognition", "2014, when GANs were introduced by Goodfellow"], correctAnswer: "2012, when AlexNet dominated the ImageNet competition", explanation: "AlexNet, built by Alex Krizhevsky under Geoffrey Hinton, won ImageNet 2012 by a huge margin, convincing the field that deep neural networks were transformative."),
        Question(id: "aih3_q2", type: .trueFalse, questionText: "Geoffrey Hinton, Yann LeCun, and Yoshua Bengio won the 2018 Turing Award for their work on deep learning.", options: ["True", "False"], correctAnswer: "True", explanation: "Often called the 'Godfathers of Deep Learning,' these three researchers received computing's highest honor for decades of foundational contributions to neural networks."),
        Question(id: "aih3_q3", type: .fillInBlank, questionText: "The __________ dataset and competition, created by Fei-Fei Li and her team, was a key catalyst for the deep learning revolution in computer vision.", options: ["ImageNet", "CIFAR", "MNIST", "COCO"], correctAnswer: "ImageNet", explanation: "Fei-Fei Li's ImageNet project provided over 14 million labeled images. The annual competition drove rapid progress in visual recognition using deep learning."),
        Question(id: "aih3_q4", type: .sortOrder, questionText: "Order these deep learning milestones:", options: ["Transformer paper published (2017)", "AlexNet wins ImageNet (2012)", "AlphaGo beats Lee Sedol (2016)", "GPT-3 demonstrates few-shot learning (2020)"], correctAnswers: ["AlexNet wins ImageNet (2012)", "AlphaGo beats Lee Sedol (2016)", "Transformer paper published (2017)", "GPT-3 demonstrates few-shot learning (2020)"], explanation: "Deep learning progress accelerated from vision breakthroughs to game mastery to new architectures to powerful language models within a single decade."),
        Question(id: "aih3_q5", type: .multipleChoice, questionText: "What three factors converged to enable the deep learning revolution?", options: ["Massive datasets, GPU computing power, and improved algorithms", "Faster internet, cheaper storage, and mobile devices", "Government grants, university partnerships, and open-source tools", "Quantum computing, blockchain technology, and cloud platforms"], correctAnswer: "Massive datasets, GPU computing power, and improved algorithms", explanation: "The convergence of big data from the internet, NVIDIA GPUs repurposed for neural networks, and algorithmic advances like dropout and batch normalization made deep learning practical."),
        Question(id: "aih3_q6", type: .multipleChoice, questionText: "DeepMind's AlphaGo victory over world champion Lee Sedol in 2016 was significant because:", options: ["Go was considered far too complex for brute-force AI approaches", "It was the first time a computer played a board game", "Lee Sedol was a relatively weak player", "The game of Go has very simple rules with few possible moves"], correctAnswer: "Go was considered far too complex for brute-force AI approaches", explanation: "Go has more possible board positions than atoms in the observable universe. AlphaGo used deep reinforcement learning, a fundamentally different approach from chess engines like Deep Blue.")
    ], order: 2, difficulty: .intermediate)
    static let lesson4 = LessonData(id: "aih_l4", title: "The Generative AI Moment", description: "AI goes mainstream", categoryId: "ai_history", questions: [
        Question(id: "aih4_q1", type: .multipleChoice, questionText: "The launch of ChatGPT in November 2022 was a watershed moment primarily because:", options: ["It made powerful AI accessible to the general public through conversation", "It was the first large language model ever created", "It was the first AI system to pass the Turing Test", "It replaced all existing search engines overnight"], correctAnswer: "It made powerful AI accessible to the general public through conversation", explanation: "While large language models existed before, ChatGPT's intuitive conversational interface brought AI capabilities to over 100 million users within two months."),
        Question(id: "aih4_q2", type: .trueFalse, questionText: "Google's 2017 'Attention Is All You Need' paper introduced the Transformer architecture that underpins all major modern large language models.", options: ["True", "False"], correctAnswer: "True", explanation: "Vaswani et al. at Google Brain introduced the Transformer architecture in 2017. It became the foundation for GPT (OpenAI), BERT (Google), LLaMA (Meta), Claude (Anthropic), and virtually all modern LLMs."),
        Question(id: "aih4_q3", type: .fillInBlank, questionText: "The 2022-2024 period saw an AI __________ among major tech companies, each racing to release competing models and products.", options: ["arms race", "partnership", "slowdown", "consolidation"], correctAnswer: "arms race", explanation: "The success of ChatGPT triggered intense competition. Google launched Gemini, Anthropic released Claude, Meta open-sourced LLaMA, and Mistral emerged in France, among many others."),
        Question(id: "aih4_q4", type: .multipleChoice, questionText: "Which company, founded by former OpenAI researchers, focuses on AI safety as a core mission?", options: ["Anthropic", "DeepMind", "Stability AI", "Hugging Face"], correctAnswer: "Anthropic", explanation: "Anthropic was founded in 2021 by Dario and Daniela Amodei, along with other former OpenAI researchers, with a focus on building safe, steerable AI systems."),
        Question(id: "aih4_q5", type: .matchPairs, questionText: "Match AI models to their organizations:", matchPairs: [
            MatchPair(term: "GPT-4", definition: "OpenAI"),
            MatchPair(term: "Gemini", definition: "Google DeepMind"),
            MatchPair(term: "Claude", definition: "Anthropic"),
            MatchPair(term: "LLaMA", definition: "Meta")
        ], explanation: "The generative AI era has produced competing models from many organizations, each with different approaches to capability and safety."),
        Question(id: "aih4_q6", type: .scenarioJudgment, questionText: "Some compare the generative AI moment to the launch of the iPhone or the early internet. Is this comparison reasonable?", options: ["Yes, it similarly made a transformative technology accessible to millions", "No, AI is too niche to compare to the internet", "It depends on future stock prices alone"], correctAnswer: "Yes, it similarly made a transformative technology accessible to millions", explanation: "Like the iPhone for mobile computing and the web browser for the internet, generative AI chatbots made sophisticated AI capabilities immediately usable by anyone, regardless of technical skill.")
    ], order: 3, difficulty: .beginner)
    static let lesson5 = LessonData(id: "aih_l5", title: "AI Pioneers", description: "The people who shaped AI", categoryId: "ai_history", questions: [
        Question(id: "aih5_q1", type: .matchPairs, questionText: "Match AI pioneers to their contributions:", matchPairs: [
            MatchPair(term: "Alan Turing", definition: "Foundational computing and intelligence theory"),
            MatchPair(term: "Fei-Fei Li", definition: "Created ImageNet, advancing computer vision"),
            MatchPair(term: "Yoshua Bengio", definition: "Pioneered neural probabilistic language models"),
            MatchPair(term: "Yann LeCun", definition: "Developed convolutional neural networks")
        ], explanation: "These pioneers span decades of AI research, from theoretical foundations to modern deep learning breakthroughs."),
        Question(id: "aih5_q2", type: .trueFalse, questionText: "Demis Hassabis co-founded DeepMind, which created AlphaGo, AlphaFold, and other groundbreaking AI systems.", options: ["True", "False"], correctAnswer: "True", explanation: "Demis Hassabis co-founded DeepMind in 2010. It was acquired by Google in 2014 and later merged with Google Brain to form Google DeepMind."),
        Question(id: "aih5_q3", type: .multipleChoice, questionText: "Timnit Gebru's influential research has focused on:", options: ["Documenting AI bias and advocating for accountability in AI systems", "Developing faster training algorithms for large models", "Building autonomous driving systems for commercial vehicles", "Designing new chip architectures for AI hardware"], correctAnswer: "Documenting AI bias and advocating for accountability in AI systems", explanation: "Timnit Gebru co-authored the landmark 'Gender Shades' study exposing racial bias in facial recognition and has been a leading voice on AI ethics and accountability."),
        Question(id: "aih5_q4", type: .fillInBlank, questionText: "Geoffrey __________, who shared the 2018 Turing Award, is known as a godfather of deep learning and later raised alarms about AI risks.", options: ["Hinton", "Bengio", "Dean", "Sutton"], correctAnswer: "Hinton", explanation: "Geoffrey Hinton spent decades advancing neural networks when they were unpopular. He left Google in 2023 to speak freely about potential dangers of advanced AI systems."),
        Question(id: "aih5_q5", type: .multipleChoice, questionText: "Andrew Ng is widely recognized for:", options: ["Making AI education accessible to millions through online courses", "Co-founding DeepMind with Demis Hassabis", "Authoring the original Transformer architecture paper", "Creating the AlphaGo reinforcement learning system"], correctAnswer: "Making AI education accessible to millions through online courses", explanation: "Andrew Ng co-founded Coursera and created deeplearning.ai. His Stanford machine learning course has been taken by millions worldwide, democratizing AI knowledge."),
        Question(id: "aih5_q6", type: .multipleChoice, questionText: "Why is diversity among AI researchers and leaders critically important?", options: ["Diverse teams build AI systems that work more fairly for everyone", "It primarily improves company marketing and public image", "It only matters for meeting regulatory compliance requirements", "Technical diversity of programming languages is more important"], correctAnswer: "Diverse teams build AI systems that work more fairly for everyone", explanation: "Research shows that homogeneous teams are more likely to overlook biases. Diverse perspectives in AI development help identify blind spots and create systems that serve all populations equitably.")
    ], order: 4, difficulty: .beginner)
    static let lesson6 = LessonData(id: "aih_l6", title: "Key AI Breakthroughs", description: "Moments that changed the field", categoryId: "ai_history", questions: [
        Question(id: "aih6_q1", type: .sortOrder, questionText: "Put these AI breakthroughs in chronological order:", options: ["AlphaGo beats Lee Sedol (2016)", "Deep Blue beats Kasparov (1997)", "AlphaFold solves protein folding (2020)", "IBM Watson wins Jeopardy! (2011)"], correctAnswers: ["Deep Blue beats Kasparov (1997)", "IBM Watson wins Jeopardy! (2011)", "AlphaGo beats Lee Sedol (2016)", "AlphaFold solves protein folding (2020)"], explanation: "These milestones show AI conquering increasingly complex domains, from chess to natural language to the ancient game of Go to fundamental biology."),
        Question(id: "aih6_q2", type: .trueFalse, questionText: "IBM's Deep Blue used deep learning to defeat world chess champion Garry Kasparov in 1997.", options: ["True", "False"], correctAnswer: "False", explanation: "Deep Blue used brute-force search evaluating 200 million positions per second plus hand-crafted heuristics. Deep learning was not practical in 1997. Modern chess engines like AlphaZero use neural networks instead."),
        Question(id: "aih6_q3", type: .multipleChoice, questionText: "Why was DeepMind's AlphaFold considered one of the greatest scientific breakthroughs of 2020?", options: ["It solved the 50-year-old protein structure prediction problem", "It was the first AI to generate realistic images", "It demonstrated the first self-driving car on public roads", "It translated between every known human language"], correctAnswer: "It solved the 50-year-old protein structure prediction problem", explanation: "Predicting how proteins fold into 3D structures had stumped biologists for decades. AlphaFold's solution has massive implications for drug discovery, disease understanding, and molecular biology worldwide."),
        Question(id: "aih6_q4", type: .fillInBlank, questionText: "The __________ architecture, introduced in the 2017 paper 'Attention Is All You Need,' became the foundation of all modern large language models.", options: ["Transformer", "Convolutional", "Recurrent", "Diffusion"], correctAnswer: "Transformer", explanation: "The Transformer's self-attention mechanism enabled parallel processing of sequences, powering GPT, BERT, PaLM, LLaMA, Claude, and virtually every modern language model."),
        Question(id: "aih6_q5", type: .multipleChoice, questionText: "What made multimodal AI models like GPT-4 and Gemini a significant leap forward?", options: ["They can process and reason across text, images, and other data types", "They were the first AI systems to understand any human language", "They were the smallest and most efficient models ever built", "They could physically interact with the real world through robotics"], correctAnswer: "They can process and reason across text, images, and other data types", explanation: "Multimodal models broke the boundary between language and vision, enabling AI to understand documents, photos, charts, and more in a unified system."),
        Question(id: "aih6_q6", type: .scenarioJudgment, questionText: "Looking at AI history from the 1950s to today, what pattern best describes how AI progress unfolds?", options: ["Long periods of research punctuated by sudden paradigm-shifting breakthroughs", "Smooth, predictable, linear improvement year over year", "Steady decline with occasional brief recoveries", "Completely random with no discernible pattern"], correctAnswer: "Long periods of research punctuated by sudden paradigm-shifting breakthroughs", explanation: "AI history shows cycles of quiet foundational research followed by dramatic breakthroughs — from expert systems to deep learning to transformers — each building on decades of prior work.")
    ], order: 5, difficulty: .intermediate)
}
